Bash(# Write the python file directly using a heredoc approach via bash subshell
# Note: osascript shell doesn''t need xcode - confirmed it ran python above
# Let''s write a python file properly
osascript -l JavaScript << 'JSEOF'
var app = Application.currentApplication\(\);
app.includeStandardAdditions = true;

// Use Python's base64 to avoid quoting issues
var result = app.doShellScript\("/usr/bin/python3 -c \\"import base64,zlib,re; data=open\('/Users/michaelmcclearn/Downloads/StayRate Elevator Pitch \(1\).pdf','rb'\).read\(\); streams=re.findall\(b'stream.{0,2}\(.*?\).{0,2}endstream',data,re.DOTALL\); texts=[]; [texts.extend\([p.decode\('latin-1','replace'\) for p in re.findall\(b'\\\\\\\\\(\([^\)\\\\\\\\\\\\\\\\]{1,200}\)\\\\\\\\\)',block\) if p.strip\(\)]\) for s in streams for block in re.findall\(b'BT\(.*?\)ET',zlib.decompress\(s\) if s[:2] in [b'x\\\\\\\\x9c',b'x\\\\\\\\x01',b'x\\\\\\\\xda',b'x\\\\\\\\x5e'] else s,re.DOTALL\) if True]; print\('\\\\\\\\n'.join\(set\(texts\)\)\)\\" 2>&1"\);
result;
JSEOF)

